@startuml
' define class FilingSystem
class "«FilingSystem»\nFilingSystem" as FilingSystem {
    data_storage: bool
    storage_limited bool
}

' define class ProcessingSystem
class "«ProcessingSystem»\nProcessingSystem" as ProcessingSystem {
    confidentiality: bool
    integrity: bool
    availability: bool
    resilient: bool
    pseudonymity: bool
    data_minimization: bool
    redundancies: bool
    tested: bool
}

' define relationship FilingSystem --> ProcessingSystem
FilingSystem --|> ProcessingSystem : 

' define class TechnicalMeasure
class "«TechnicalMeasure»\nTechnicalMeasure" as TechnicalMeasure {
    stereotype: GENERIC_STEREOTYPE
    category: TECHNOLOGY_CATEGORY
}

' define relationship TechnicalMeasure --> ProcessingSystem
TechnicalMeasure --|> ProcessingSystem : secures

' define class Controller
class "«Controller»\nController" as Controller {
    processor: bool
}

' define relationship Controller --> ProcessingSystem
Controller --|> ProcessingSystem : implements

' define class Processor
class "«Processor»\nProcessor" as Processor {
}

' define class Recipient
class "«Recipient»\nRecipient" as Recipient {
}

' define class ThirdParty
class "«ThirdParty»\nThirdParty" as ThirdParty {
}

' define class DataHandler
class "«DataHandler»\nDataHandler" as DataHandler {
}

' define relationship Controller --> DataHandler
Controller --|> DataHandler : 
' define relationship Processor --> DataHandler
Processor --|> DataHandler : 
' define relationship Recipient --> DataHandler
Recipient --|> DataHandler : 
' define relationship ThirdParty --> DataHandler
ThirdParty --|> DataHandler : 

' define class ProcessingTask
class "«ProcessingTask»\nProcessingTask" as ProcessingTask {
    logged : bool
}

' define relationship ProcessingSystem --> ProcessingTask
ProcessingSystem --|> ProcessingTask : performs

' define class Artifact
class "«Artifact»\nProcessingLog" as Artifact {
    name: bool
    contact_details: bool
    personal_data_category: bool
    data_storage_period: bool
    technical_measures: bool
    recipients: Array
}

' define relationship ProcessingTask --> Artifact
ProcessingTask --|> Artifact : manifests

' define class DataSubject
class "«DataSubject»\nDataSubject" as DataSubject {
    minor : false
}

' define class PersonalData
class "«PersonalData»\nPersonalData" as PersonalData {
    category: DATA_CATEGORY
}

' define relationship DataHandler --> PersonalData
DataHandler --|> PersonalData : receives
' define relationship DataSubject --> PersonalData
DataSubject --|> PersonalData : provides

' define class Purpose
class "«Purpose»\nPurpose" as Purpose {
    consent: CLASS consent
    contract_performance: bool
    controller_legal_obligation: bool
    vital_interest_protection: bool
    public_interest: bool
    legitimate_interest: bool
}

' define class SpecialPurpose
class "«SpecialPurpose»\nSpecialPurpose" as SpecialPurpose {
    consent: CLASS consent
    employment_purpose: bool
    social_purpose: bool
    vital_interest: bool
    nonprofit_body: bool
    public_from_subject: bool
    legal_claim: bool
    public_interest: bool
    preventive_medicine: bool
    occupational_medicine: bool
    public_health: bool
    archiving: bool
    statistical_purposes: bool
}

' define relationship PersonalData --> SpecialPurpose
PersonalData --|> SpecialPurpose : requires

' define class Consent
class "«Consent»\nConsent" as Consent {
}

' define relationship PersonalData --> Consent
PersonalData --|> Consent : requires
' define relationship Purpose --> Consent
Purpose --|> Consent : 

' define class Artifact_1
class "«Artifact»\nConsentAgreement" as Artifact_1 {
    clear_purpose: bool
    unambiguous: bool
    affirmative_action: bool
    distinguishable: bool
    specific: bool
    withdrawable: bool
    freely_given: bool
}

' define relationship Consent --> Artifact_1
Consent --|> Artifact_1 : manifests

